  qrCodePath: "/images/line-qr.png",
} as const;

// Navigation items
export interface NavItem {
  label: string;
  href: string;
  children?: NavItem[];
}

export const NAV_ITEMS: NavItem[] = [
  { label: "ホーム", href: "/" },
  {
