      {/* Icon */}
      <div className="w-14 h-14 rounded-xl bg-sakura-50 flex items-center justify-center mb-6 group-hover:bg-sakura-100 transition-colors">
        <IconComponent className="w-7 h-7 text-sakura-600" />
      </div>

      {/* Content */}
      <h3 className="text-xl font-bold text-neutral-900 mb-3 group-hover:text-sakura-600 transition-colors">
        {title}
      </h3>
      <p className="text-neutral-600 text-sm leading-relaxed mb-4">
        {description}
      </p>

      {/* Link */}
      <div className="flex items-center text-sakura-600 font-medium text-sm">
        <span>詳しく見る</span>
        <ArrowRight className="w-4 h-4 ml-1 group-hover:translate-x-1 transition-transform" />
      </div>
    </a>
  );
}

